  1	import React, { FC, ReactNode } from 'react';
  2	import classnames from 'classnames';
  3	
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  DescriptionListDescription,
  8	  DescriptionListGroup,
  9	  DescriptionListTermHelpText,
 10	  Flex,
 11	  FlexItem,
 12	} from '@patternfly/react-core';
 13	import { PencilAltIcon } from '@patternfly/react-icons';
 14	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 15	
 16	import { DetailItemHeader } from './DetailItemHeader';
 17	import EditButtonWithTooltip from './EditButtonWithTooltip';
 18	
 19	import './DetailItem.scss';
 20	
 21	type DetailItemProps = {
 22	  popoverBodyContent?: ReactNode;
 23	  breadcrumb?: string;
 24	  className?: string;
 25	  testId?: string;
 26	  description: ReactNode | string;
 27	  header?: ReactNode;
 28	  editOnTitleJustify?: boolean;
 29	  isDisabled?: boolean;
 30	  isEdit?: boolean;
 31	  isPopover?: boolean;
 32	  headerBadge?: ReactNode;
 33	  messageOnDisabled?: string;
 34	  moreInfoURL?: string;
 35	  onEditClick?: () => void;
 36	  showEditOnTitle?: boolean;
 37	};
 38	
 39	const DetailItem: FC<DetailItemProps> = ({
 40	  popoverBodyContent,
 41	  breadcrumb,
 42	  className,
 43	  testId,
 44	  description,
 45	  header,
 46	  editOnTitleJustify = false,
 47	  isDisabled,
 48	  isEdit,
 49	  isPopover,
 50	  headerBadge,
 51	  messageOnDisabled,
 52	  moreInfoURL,
 53	  onEditClick,
 54	  showEditOnTitle,
 55	}) => {
 56	  const { t } = useNMStateTranslation();
 57	  const NotAvailable = <span className="text-muted">{t('Not available')}</span>;
 58	
 59	  return (
 60	    <DescriptionListGroup className={classnames('pf-c-description-list__group', className)}>
 61	      <DescriptionListTermHelpText className="pf-c-description-list__term">
 62	        <Flex
 63	          justifyContent={{
 64	            default: editOnTitleJustify ? 'justifyContentSpaceBetween' : 'justifyContentFlexStart',
 65	          }}
 66	        >
 67	          {(popoverBodyContent || breadcrumb || header || headerBadge || moreInfoURL) && (
 68	            <FlexItem>
 69	              <DetailItemHeader
 70	                bodyContent={popoverBodyContent}
 71	                breadcrumb={breadcrumb}
 72	                descriptionHeader={header}
 73	                isPopover={isPopover}
 74	                label={headerBadge}
 75	                moreInfoURL={moreInfoURL}
 76	              />
 77	            </FlexItem>
 78	          )}
 79	          {isEdit && showEditOnTitle && (
 80	            <FlexItem>
 81	              <Button
 82	                data-test-id={`${testId}-edit`}
 83	                isDisabled={isDisabled}
 84	                isInline
 85	                onClick={onEditClick}
 86	                variant={ButtonVariant.link}
 87	              >
 88	                {t('Edit')}
 89	                <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
 90	              </Button>
 91	            </FlexItem>
 92	          )}
 93	        </Flex>
 94	      </DescriptionListTermHelpText>
 95	
 96	      <DescriptionListDescription
 97	        className="pf-c-description-list__description"
 98	        data-test-id={testId}
 99	      >
100	        {isEdit && !showEditOnTitle ? (
101	          <EditButtonWithTooltip
102	            isEditable={!isDisabled}
103	            onEditClick={onEditClick}
104	            testId={testId}
105	            tooltipContent={messageOnDisabled}
106	          >
107	            {description ?? NotAvailable}
108	          </EditButtonWithTooltip>
109	        ) : (
110	          description
111	        )}
112	      </DescriptionListDescription>
113	    </DescriptionListGroup>
114	  );
115	};
116	
117	export default DetailItem;

